record.field:
for source in records:
    source.with_delay(
        channel="root.newsassistant",
        description=f"Bulk scrape: {source.name}",
    )._scrape_listing()
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Scrape Jobs Queued",
        "message": f"{len(records)} source(s) queued for scraping.",
        "type": "info",
        "sticky": False,
    },
}

count = 0
for article in records.filtered(lambda a: a.state != 'skipped'):
    article.snapshot_id.with_delay(
        channel="root.newsassistant",
        description=f"Bulk re-extract: {article.title[:50]}",
    )._extract_articles()
    count += 1
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Re-extract Jobs Queued",
                "message": f"{count} article(s) queued for re-extraction.",
        "type": "info",
        "sticky": False,
    },
}

records.filtered(lambda a: a.state != 'skipped').write({"state": "skipped", "active": False})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Skipped",
        "message": f"{len(records)} article(s) marked as skipped and archived.",
        "type": "info",
        "sticky": False,
    },
}

records.write({
    "state": "pending",
    "status_message": False,
    "last_error_date": False,
    "retry_count": 0,
    "active": True,
})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Reset",
        "message": f"{len(records)} article(s) reset to pending and unarchived.",
        "type": "info",
        "sticky": False,
    },
}
